Willowshore Random Encounter Flat Check.command:
let dc = 10;

const actor = game.actors.find(a => a.type === "party");
const members = actor.members;

if (!actor || !Array.isArray(actor.members)) {
  ui.notifications.error("Party actor or members not found!");
  return;
}

actor.members.forEach((member) => {
  const selectedActivities = member.system?.exploration;

  if (!Array.isArray(selectedActivities)) return;

  selectedActivities.forEach((activity) => {
    const item = member.items.get(activity);
    if (!item?.name) return;

    if (["Hustle", "Search"].includes(item.name)) {
      dc -= 2;
    } else if (["Avoid Notice", "Scout"].includes(item.name)) {
      dc += 1;
    }
  });
});

const flatCheckRoll = await new Roll('1d20').evaluate();

if (game.dice3d) {
  await game.dice3d.showForRoll(flatCheckRoll, game.user, true);
}

const successText = `DC${dc} Roll Result: ${flatCheckRoll.total}<hr>The party comes across a Random Encounter in Willowshore!`;
const failText = `DC${dc} Roll Result: ${flatCheckRoll.total}<hr>The party is safe... for now.`;

const hidden = true;
const success = flatCheckRoll.result >= dc;

const content = success
  ? successText
  : failText ;

await ChatMessage.create({
  content: content,
  whisper: hidden ? ChatMessage.getWhisperRecipients("GM").map((u) => u.id) : null,
  blind: hidden
});

if (success){
  const table = await fromUuid("Compendium.pf2e-season-of-ghosts-tools.season-of-ghosts-rolltables.RollTable.ixB77nbzx0lPqi9S");
  await table.draw({roll: true, displayChat: true, rollMode: CONST.DICE_ROLL_MODES.PRIVATE});
  console.log(table);
}
